import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { libraryCardsAPI } from '../services/api';

const RequestCardPage = () => {
  const { currentUser } = useAuth();

  const [notes, setNotes] = useState('');
  const [status, setStatus] = useState(null); // 'idle', 'loading', 'success', 'error'
  const [errorMsg, setErrorMsg] = useState('');
  const [existingCard, setExistingCard] = useState(null);

  useEffect(() => {
    // Check if they already have a card
    libraryCardsAPI.getMyCard()
      .then(res => setExistingCard(res.data))
      .catch(err => {
        // 404 means no card found, which is fine
        if (err.statusCode !== 404) console.error(err);
      });
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setStatus('loading');
    setErrorMsg('');

    try {
      const res = await libraryCardsAPI.apply({ notes });
      setExistingCard(res.data);
      setStatus('success');
    } catch (err) {
      console.error(err);
      setStatus('error');
      setErrorMsg(err.message || 'Failed to submit application.');
    }
  };

  return (
    <div className="page-wrapper">
      <div className="container">
        <div className="row justify-content-center">
          <div className="col-lg-8">
            <div className="mb-4">
              <h2 className="section-title">
                <i className="bi bi-credit-card me-2" style={{ color: 'var(--accent)' }}></i>
                Request Library Card
              </h2>
              <p className="section-subtitle">Apply for a digital library card to borrow books</p>
            </div>

            {existingCard ? (
              <div className="lib-card p-4 text-center">
                <div style={{ width: 80, height: 80, borderRadius: '50%', background: 'rgba(99,102,241,.1)', margin: '0 auto 1rem', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                  <i className="bi bi-person-badge" style={{ fontSize: '2.5rem', color: '#6366f1' }}></i>
                </div>
                <h4>Your Library Card</h4>
                <p className="text-muted">Status: <span className={`badge-role badge-${existingCard.status.toLowerCase()}`}>{existingCard.status}</span></p>
                {existingCard.cardNumber && <div className="mt-3" style={{ fontSize: '1.2rem', fontFamily: 'monospace', padding: '10px', background: '#f5f5f5', borderRadius: '5px', display: 'inline-block' }}>{existingCard.cardNumber}</div>}

                {existingCard.status === 'rejected' && (
                  <div className="alert alert-danger mt-3 text-start">
                    <strong>Rejection Reason:</strong> {existingCard.rejectionReason || 'No reason provided.'}
                  </div>
                )}
                {existingCard.status === 'suspended' && (
                  <div className="alert alert-warning mt-3 text-start">
                    <strong>Suspension Reason:</strong> {existingCard.suspensionReason || 'No reason provided.'}
                  </div>
                )}
              </div>
            ) : (
              <div className="lib-card p-4">
                {status === 'success' && (
                  <div className="alert alert-success lib-alert mb-4">
                    <i className="bi bi-check-circle-fill me-2"></i>Application submitted successfully! It is now pending review.
                  </div>
                )}

                {status === 'error' && (
                  <div className="alert alert-danger mb-4">{errorMsg}</div>
                )}

                {status !== 'success' && (
                  <form onSubmit={handleSubmit}>
                    <div className="mb-3">
                      <label className="lib-label">Student Name</label>
                      <input type="text" className="form-control" value={currentUser?.name || ''} disabled />
                    </div>

                    <div className="mb-3">
                      <label className="lib-label">Student ID</label>
                      <input type="text" className="form-control" value={currentUser?.studentId || ''} disabled />
                    </div>

                    <div className="mb-3">
                      <label className="lib-label">Application Notes (Optional)</label>
                      <textarea 
                        className="form-control" 
                        rows="3" 
                        value={notes} 
                        onChange={(e) => setNotes(e.target.value)}
                        placeholder="Any additional information for the librarian..."
                      ></textarea>
                    </div>

                    <button type="submit" className="btn btn-lib-primary" disabled={status === 'loading'}>
                      {status === 'loading' ? 'Submitting...' : 'Submit Application'}
                    </button>
                  </form>
                )}
              </div>
            )}

            <div className="alert lib-alert alert-info mt-3" style={{ background: 'rgba(99,102,241,.08)', border: '1px solid rgba(99,102,241,.2)', color: '#4338ca' }}>
              <i className="bi bi-info-circle me-2"></i>
              <strong>Note:</strong> Library cards are typically approved within 1–2 working days. Once approved, you can visit the library to get books issued to your account.
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default RequestCardPage;
